SourceCode.Declaration:
[ExtensionOf(classStr(SalesCopying))]
final class FWFTextBlockSalesCopying_Extension
{
    private NoYes   copyHeaderTB;
    private NoYes   copyLineTB;

}

Method.Source:
public NoYes parmCopyHeaderTextBlock(NoYes _copyHeaderTB = copyHeaderTB)
{
    copyHeaderTB = _copyHeaderTB;
    return copyHeaderTB;
}

public NoYes parmCopyLineTextBlock(NoYes _copyLineTB = copyLineTB)
{
    copyLineTB = _copyLineTB;
    return copyLineTB;
}

protected Common copyFromSourceTable(TmpFrmVirtual _tmpFrmVirtualHeader)
{
    FWFTextBlockInstance    sourceInstance, targetInstance;
    Common                  sourceRecord = next copyFromSourceTable(_tmpFrmVirtualHeader);

    if (this.parmCopyHeaderTextBlock())
    {
        //delete texts from setup
        delete_from targetInstance
            where targetInstance.RefTableId == salesTable.TableId
               && targetInstance.RefRecId   == salesTable.RecId;

        while select sourceInstance
            where sourceInstance.RefTableId == sourceRecord.TableId
               && sourceInstance.RefRecId   == sourceRecord.RecId
        {
            targetInstance = sourceInstance.copyToTarget(salesTable, true);
        }
    }

    return sourceRecord;
}

protected void copyLine(SalesLine _salesLine, SalesLineCopyFromSource _salesLineCopyFromSource)
{
    FWFTextBlockInstance    sourceInstance, targetInstance;
    Common                  sourceRecord;

    next copyLine(_salesLine, _salesLineCopyFromSource);

    sourceRecord = _salesLineCopyFromSource.retrieveSource();

    if (this.parmCopyLineTextBlock())
    {
        //delete texts from setup
        delete_from targetInstance
            where targetInstance.RefTableId == _salesLine.TableId
               && targetInstance.RefRecId   == _salesLine.RecId;

        while select sourceInstance
            where sourceInstance.RefTableId == sourceRecord.TableId
               && sourceInstance.RefRecId   == sourceRecord.RecId
        {
            targetInstance = sourceInstance.copyToTarget(_salesLine, true);
        }
    }
}
